using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer;

/// <summary>
/// MCP tools that wrap a REST API (JSONPlaceholder as an example).
/// Non-static class — services are injected via constructor.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The numeric ID of the post (1–100).")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var post = await httpClient.GetFromJsonAsync<JsonElement>(
            $"posts/{id}", cancellationToken);
        return JsonSerializer.Serialize(post, JsonOptions);
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID. Omit to list all.")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var url = userId.HasValue ? $"posts?userId={userId}" : "posts";
        logger.LogInformation("Listing posts: {Url}", url);
        var posts = await httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);
        return JsonSerializer.Serialize(posts, JsonOptions);
    }

    [McpServerTool, Description("Search for users by name (case-insensitive substring match).")]
    public async Task<string> SearchUsers(
        [Description("Substring to match against user names.")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching users for '{Query}'", query);
        var users = await httpClient.GetFromJsonAsync<JsonElement[]>(
            "users", cancellationToken);

        var matches = users!
            .Where(u => u.GetProperty("name").GetString()!
                .Contains(query, StringComparison.OrdinalIgnoreCase))
            .ToArray();

        return JsonSerializer.Serialize(matches, JsonOptions);
    }
}

